checks.run:
kubectl --context kind-kubeadv-core create namespace m5-check --dry-run=client -o yaml | kubectl --context kind-kubeadv-core apply -f - >/dev/null; printf 'apiVersion: kubeadv.io/v1alpha1
kind: Website
metadata: {name: celcheck, namespace: m5-check}
spec: {host: c.io, replicas: 9}
' | kubectl --context kind-kubeadv-core apply -f - 2>&1 | head -1; kubectl --context kind-kubeadv-core delete namespace m5-check --wait=false >/dev/null 2>&1

kubectl --context kind-kubeadv-core create namespace m5-check2 --dry-run=client -o yaml | kubectl --context kind-kubeadv-core apply -f - >/dev/null; printf 'apiVersion: kubeadv.io/v1alpha1
kind: Website
metadata: {name: chk, namespace: m5-check2}
spec: {host: chk.io, replicas: 1}
' | kubectl --context kind-kubeadv-core apply -f - >/dev/null; for i in $(seq 1 20); do R=$(kubectl --context kind-kubeadv-core -n m5-check2 get website chk -o jsonpath='{.status.conditions[?(@.type=="Ready")].status}' 2>/dev/null); [ "$R" = "True" ] && break; sleep 3; done; echo "ready=${R}"; kubectl --context kind-kubeadv-core delete namespace m5-check2 --wait=false >/dev/null 2>&1

kubectl --context kind-kubeadv-core create namespace m5-check3 --dry-run=client -o yaml | kubectl --context kind-kubeadv-core apply -f - >/dev/null; printf 'apiVersion: kubeadv.io/v1alpha1
kind: Website
metadata: {name: own, namespace: m5-check3}
spec: {host: own.io, replicas: 1}
' | kubectl --context kind-kubeadv-core apply -f - >/dev/null; for i in $(seq 1 15); do O=$(kubectl --context kind-kubeadv-core -n m5-check3 get deploy web-own -o jsonpath='{.metadata.ownerReferences[?(@.controller==true)].kind}' 2>/dev/null); [ -n "$O" ] && break; sleep 3; done; F=$(kubectl --context kind-kubeadv-core -n m5-check3 get website own -o jsonpath='{.metadata.finalizers[0]}' 2>/dev/null); echo "owner=${O} finalizer=${F}"; kubectl --context kind-kubeadv-core delete namespace m5-check3 --wait=false >/dev/null 2>&1
